import React, { useCallback, useRef, useState } from 'react';
import { Layer, Stage } from 'react-konva';
import './App.css';
import Toolbar from './components/Toolbar';
import PenTool from './tools/PenTool';

function App() {
  const [tool, setTool] = useState('pen');
  const [lines, setLines] = useState([]);
  const stageRef = useRef();
  const [stagePos, setStagePos] = useState({ x: 0, y: 0 });
  const [stageScale, setStageScale] = useState(1);

  // Generic line management functions
  const handleLineAdd = useCallback((newLine) => {
    setLines(prevLines => [...prevLines, newLine]);
  }, []);

  const handleLineUpdate = useCallback((lineId, updateFn) => {
    setLines(prevLines => {
      const newLines = [...prevLines];
      const lineIndex = newLines.findIndex(line => line.id === lineId);
      if (lineIndex >= 0) {
        newLines[lineIndex] = updateFn(newLines[lineIndex]);
      }
      return newLines;
    });
  }, []);

  // Canvas controls (zoom, pan)
  const handleWheel = useCallback((e) => {
    e.evt.preventDefault();

    const stage = stageRef.current;
    const oldScale = stage.scaleX();
    const pointer = stage.getPointerPosition();

    const mousePointTo = {
      x: (pointer.x - stage.x()) / oldScale,
      y: (pointer.y - stage.y()) / oldScale,
    };

    const newScale = e.evt.deltaY > 0 ? oldScale * 0.9 : oldScale * 1.1;

    const newPos = {
      x: pointer.x - mousePointTo.x * newScale,
      y: pointer.y - mousePointTo.y * newScale,
    };

    setStageScale(newScale);
    setStagePos(newPos);
  }, []);

  // Handle pinch-to-zoom for tablets (only when not using pen tool)
  const handleTouchMove = useCallback((e) => {
    // Only handle pinch-to-zoom when pen tool is not active
    if (tool !== 'pen' && e.evt.touches && e.evt.touches.length === 2) {
      e.evt.preventDefault();

      const touch1 = e.evt.touches[0];
      const touch2 = e.evt.touches[1];

      const dist = Math.sqrt(
        Math.pow(touch2.clientX - touch1.clientX, 2) +
        Math.pow(touch2.clientY - touch1.clientY, 2)
      );

      if (!stageRef.current.lastDist) {
        stageRef.current.lastDist = dist;
        return;
      }

      const scale = stageScale * (dist / stageRef.current.lastDist);
      setStageScale(Math.max(0.1, Math.min(5, scale)));
      stageRef.current.lastDist = dist;
    }
  }, [stageScale, tool]);

  const handleTouchEnd = useCallback(() => {
    if (stageRef.current) {
      stageRef.current.lastDist = 0;
    }
  }, []);

  return (
    <div className="app">
      <Toolbar 
        activeTool={tool} 
        onToolChange={setTool}
      />
      <div className="canvas-container">
        <Stage
          ref={stageRef}
          width={window.innerWidth}
          height={window.innerHeight}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          onWheel={handleWheel}
          scaleX={stageScale}
          scaleY={stageScale}
          x={stagePos.x}
          y={stagePos.y}
          draggable={tool === 'pan'}
        >
          <Layer>
            {/* Modular Tools */}
            <PenTool
              isActive={tool === 'pen'}
              onLineAdd={handleLineAdd}
              onLineUpdate={handleLineUpdate}
              stagePos={stagePos}
              stageScale={stageScale}
              lines={lines}
            />

            {/* Future tools will be added here */}
            {/* 
            <EraserTool
              isActive={tool === 'eraser'}
              onLineAdd={handleLineAdd}
              onLineUpdate={handleLineUpdate}
              stagePos={stagePos}
              stageScale={stageScale}
              lines={lines}
            />
            */}
          </Layer>
        </Stage>
      </div>
    </div>
  );
}

export default App;
